// test/platform.test.mjs — four-platform artifact emission tests (PLAN-TASK-008;
// SPEC-BUILD-001, SPEC-PLATFORM-001, SPEC-TRIGGER-001). Covers:
//   1. Self-conformance: build({ check: true }) reports every artifact byte-identical to the
//      committed generated/ tree (the SPEC-BUILD-001 gate that `node src/build/build.mjs --check`
//      also exercises via the CLI).
//   2. A golden snapshot per platform, masking the shared-body fragment (RISK-DET-001 /
//      DES-BUILD-001 "掩蔽共享正文段以降噪") so the pinned expectation is immune to prose edits in
//      fragments/shared/body.md while still catching any structural regression in how
//      src/build/platforms.mjs assembles frontmatter, section order, and argument placeholders.
//      These golden constants were captured from generated/ output that was manually verified
//      (frontmatter shape, guard text placement, valid TOML) before being pinned here — a future
//      change must re-verify and deliberately re-pin them, not silently pass by construction.
//   3. Structural/content invariants: every platform's artifact exists on disk, every platform's
//      description carries the SPEC-TRIGGER-001 negative-invocation guard verbatim, only Claude's
//      artifact sets `disable-model-invocation`, and the Gemini artifact is syntactically valid
//      TOML with the required `prompt` key.
//   4. Determinism: rendering the same context twice through platforms.mjs's emitPlatform is
//      byte-identical (no timestamps/randomness — RISK-DET-001), independent of the generated/
//      tree on disk.
import test from 'node:test';
import assert from 'node:assert/strict';
import { existsSync, readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

import { build } from '../src/build/build.mjs';
import { emitPlatform } from '../src/build/platforms.mjs';
import { REGISTRY } from '../src/build/registry.mjs';

const HERE = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = join(HERE, '..');
const GENERATED_DIR = join(REPO_ROOT, 'generated');

// The single sentence every platform's description/frontmatter must carry verbatim
// (SCOPE-IN-006, SPEC-TRIGGER-001) — read from its one source of authorship, not duplicated here.
const GUARD_TEXT = readFileSync(join(REPO_ROOT, 'fragments', 'skill', 'triggers.md'), 'utf8').trim();

// The shared cross-platform prose (DES-BUILD-001) masked out of the golden snapshots below so a
// prose-only edit to this file doesn't require re-pinning every platform's structural golden.
const SHARED_BODY = readFileSync(join(REPO_ROOT, 'fragments', 'shared', 'body.md'), 'utf8').trim();
const MASK = '<<SHARED_BODY>>';

function maskSharedBody(content) {
  return content.split(SHARED_BODY).join(MASK);
}

const PLATFORM_FILES = {
  claude: join(GENERATED_DIR, 'claude', 'SKILL.md'),
  codex: join(GENERATED_DIR, 'codex', 'code-guidelines.md'),
  opencode: join(GENERATED_DIR, 'opencode', 'code-guidelines.md'),
  gemini: join(GENERATED_DIR, 'gemini', 'code-guidelines.toml'),
};

/**
 * Parse the narrow TOML shape platforms.mjs emits for Gemini: a single-quoted literal
 * `description = '...'` line followed by a triple-single-quoted literal multi-line
 * `prompt = '''...'''` block, and nothing else. Zero-deps (no TOML library) — this is a
 * deliberately minimal, grammar-accurate parser for exactly the two keys this artifact uses,
 * not a general-purpose TOML implementation.
 */
function parseGeminiToml(text) {
  const lines = text.split('\n');
  const descMatch = lines[0]?.match(/^description = '(.*)'$/);
  if (!descMatch) {
    throw new Error(`line 1 is not a valid TOML single-quoted-literal "description": ${lines[0]}`);
  }
  if (lines[1] !== "prompt = '''") {
    throw new Error(`line 2 is not a valid TOML triple-single-quoted-literal "prompt" opener: ${lines[1]}`);
  }
  const closingIdx = lines.indexOf("'''", 2);
  if (closingIdx === -1) {
    throw new Error('prompt triple-single-quoted literal string is never closed with a bare \'\'\' line');
  }
  const trailing = lines
    .slice(closingIdx + 1)
    .join('\n')
    .trim();
  if (trailing !== '') {
    throw new Error(`unexpected content after the closing '''`);
  }
  return { description: descMatch[1], prompt: lines.slice(2, closingIdx).join('\n') };
}

// --- self-conformance (SPEC-BUILD-001) -------------------------------------------------------

test('self-conformance: build({ check: true }) reports every artifact matching committed generated/', async () => {
  const results = await build({ check: true });
  assert.equal(results.length, 4, 'one artifact per platform in REGISTRY');
  for (const r of results) {
    assert.equal(r.matches, true, `${r.path} does not match a fresh in-memory build`);
  }
});

