test('negative-invocation guard: all four platform artifacts carry the SPEC-TRIGGER-001 guard sentence verbatim', () => {
  for (const [platform, path] of Object.entries(PLATFORM_FILES)) {
    const content = readFileSync(path, 'utf8');
    assert.ok(content.includes(GUARD_TEXT), `${platform} artifact is missing the negative-invocation guard sentence`);
  }
});

test('disable-model-invocation: appears ONLY in the claude artifact, on no other platform', () => {
  assert.ok(
    readFileSync(PLATFORM_FILES.claude, 'utf8').includes('disable-model-invocation'),
    'claude must set disable-model-invocation'
  );
  for (const platform of ['codex', 'opencode', 'gemini']) {
    assert.ok(
      !readFileSync(PLATFORM_FILES[platform], 'utf8').includes('disable-model-invocation'),
      `${platform} must NOT contain "disable-model-invocation" (Claude-only hard-disable flag, SPEC-TRIGGER-001)`
    );
  }
});

test('gemini artifact is syntactically valid TOML with the required "prompt" key and the guard as "description"', () => {
  const content = readFileSync(PLATFORM_FILES.gemini, 'utf8');
  const parsed = parseGeminiToml(content);
  assert.equal(parsed.description, GUARD_TEXT);
  assert.ok(parsed.prompt.length > 0, 'prompt must be non-empty (TOML required field, SPEC-PLATFORM-001)');
  assert.ok(parsed.prompt.includes('## Purpose'));
  assert.ok(parsed.prompt.includes('## Triggers'));
  assert.ok(parsed.prompt.includes('## Behavior'));
  assert.ok(parsed.prompt.includes('## Output'));
});

